from openai import OpenAI

client = OpenAI()

def extract_propositions(passage: str, source: str, page: int) -> list[dict]:
    """
    Use an LLM to extract atomic propositions from a passage.
    Each proposition is a self-contained factual claim.
    """
    response = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[
            {
                "role": "system",
                "content": (
                    "Extract atomic propositions from the passage. "
                    "Each proposition must be a single self-contained factual claim. "
                    "Output one proposition per line. No bullets."
                ),
            },
            {"role": "user", "content": passage},
        ],
        temperature=0,
    )
    propositions = [
        line.strip()
        for line in response.choices[0].message.content.splitlines()
        if line.strip()
    ]
    return [
        {"text": prop, "source": source, "page": page}
        for prop in propositions
    ]

# Example output for "Acme Corp reported Q3 2025 revenue of $2.1B, up 18% YoY."
# → ["Acme Corp reported Q3 2025 revenue of $2.1B.",
#    "Acme Corp Q3 2025 revenue grew 18% year-over-year."]
